icon: 'pi-inbox', color: 'blue' }, requisitos: { clave: 'requisitos', label: 'Requisitos pendientes', valor: datos.value?.requisitos_pendientes_actuales || 0, detalle: 'del paso vigente', ruta: '/expedientes?requisitos=pendientes', icon: 'pi-list-check', color: 'amber' } }; if (auth.isAdmin) return [k.proceso, k.graduados, k.caducos, k.vencePronto]; if (auth.isDirectora) return [k.candidatos, k.requisitos, k.vinculados, k.vencePronto]; if (auth.isSecretaria) return [k.candidatos, k.requisitos, k.vinculados, k.sinExp]; if (auth.rol === 'Recepcion') return [k.nuevos, k.sinExp, k.candidatos, k.vinculados]; return [k.candidatos, k.requisitos, k.vinculados, k.errores] })
function colorSerie(indice) { return coloresSeries[indice % coloresSeries.length] }
function puntosSerieArray(serie) { return (serie.valores || []).map((valor, indice) => ({ x: 20 + (indice * (520 / 11)), y: 126 - ((valor / maxRitmoSeries.value) * 98) })) }
function puntosSerie(serie) { return puntosSerieArray(serie).map(punto => `${punto.x},${punto.y}`).join(' ') }
function porcentajeContinuidad(valor) { if (!valor) return '0%'; return `${Math.max((valor / maxContinuidad.value) * 100, 2)}%` }; function porcentajeContinuidadTotal(valor) { const total = continuidad.value.reduce((suma, tramo) => suma + tramo.valor, 0); return total ? `${(valor / total) * 100}%` : '0%' }; function etiquetaMes(valor) { return valor?.split(' ')[0] || '' }; function agregarAnio(ruta) { if (!anioSeleccionado.value || !ruta.startsWith('/expedientes')) return ruta; return `${ruta}${ruta.includes('?') ? '&' : '?'}anio=${anioSeleccionado.value}` }; function irA(ruta) { router.push(agregarAnio(ruta)) }; function irExpedientes(params) { const query = new URLSearchParams(params); if (anioSeleccionado.value) query.set('anio', anioSeleccionado.value); router.push(`/expedientes${query.toString() ? `?${query.toString()}` : ''}`) }; function abrirAlerta(alerta) { if (!alerta) return; if (alerta.accion === 'vencimientos') return abrirVencimientos(); if (alerta.accion === 'caducos') return irExpedientes({ estado: 'Caduco' }); if (alerta.accion === 'tickets') return router.push('/bandeja?antiguedad_dias=15'); if (alerta.accion === 'trayectorias') return irExpedientes({ estado: 'En Proceso', antiguedad_anios: 5 }) }; function abrirItemAlerta(item) { if (item.tipo === 'ticket') return router.push(`/bandeja/${item.uuid}`); return router.push(`/expedientes/${item.uuid}`) }; async function seleccionarAlerta(alerta) { alertaSeleccionada.value = alerta.clave; if (alerta.clave === 'vence_pronto') return; cargandoAlerta.value = true; detalleAlerta.value = []; try { const params = { page: 1, per_page: 50, anio: anioSeleccionado.value || undefined }; if (alerta.clave === 'caducos') { const res = await api.get('/expedientes', { params: { ...params, estado: 'Caduco' } }); detalleAlerta.value = (res.data.data || []).map(item => ({ clave: item.uuid, tipo: 'expediente', uuid: item.uuid, titulo: item.nombre_alumno, detalle: `Paso ${item.id_paso_actual} · ${item.codigo_alumno || 'Sin código'}`, fecha: 'Vigencia vencida' })) } else if (alerta.clave === 'tickets_15') { const res = await api.get('/tickets', { params: { antiguedad_dias: 15, page: 1, per_page: 50, sort_by: 'fecha', sort_dir: 'asc' } }); detalleAlerta.value = (res.data.data || []).map(item => ({ clave: item.uuid, tipo: 'ticket', uuid: item.uuid, titulo: `#${item.numero_visual} · ${item.nombre_estudiante_osticket || 'Sin nombre'}`, detalle: item.asunto || 'Sin asunto', fecha: formatoFecha(item.fecha) })) } else if (alerta.clave === 'trayectoria_5') { const res = await api.get('/expedientes', { params: { ...params, estado: 'En Proceso', antiguedad_anios: 5 } }); detalleAlerta.value = (res.data.data || []).map(item => ({ clave: item.uuid, tipo: 'expediente', uuid: item.uuid, titulo: item.nombre_alumno, detalle: `Paso ${item.id_paso_actual} · ${item.codigo_alumno || 'Sin código'}`, fecha: '5 años o más' })) } } catch (err) { error.value = err.response?.data?.detail || 'No se pudieron cargar los casos de la alerta.' } finally { cargandoAlerta.value = false } }; function textoEstadoPersona(valor) { return { 'En Proceso': 'En proceso', Observado: 'Observado', Archivado_Graduado: 'Graduado', Caduco: 'Caduco' }[valor] || valor || 'Sin estado' }; function badgeEstadoPersona(valor) { if (valor === 'Archivado_Graduado') return 'badge-graduado'; if (valor === 'Observado') return 'badge-observado'; if (valor === 'Caduco') return 'badge-caduco'; return 'badge-proceso' }; function formatoFecha(fecha) { return fecha ? new Date(`${fecha}T00:00:00`).toLocaleDateString('es-PE', { day: '2-digit', month: 'short', year: 'numeric' }) : 'Sin fecha' }; function formatFechaHora(fecha) { return fecha ? new Date(`${fecha}${fecha.endsWith('Z') ? '' : 'Z'}`).toLocaleString('es-PE', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' }) : 'Sin registro' }; function faseTexto(fase) { if (!fase) return 'Sin registro'; return { ok: 'Correcta', error: 'Error', ejecutando: 'Ejecutando', pendiente: 'Pendiente' }[fase.estado] || fase.estado }
formatoFecha = (fecha) => {
  const partes = String(fecha || '').match(/^(\d{4})-(\d{2})-(\d{2})/)
  if (!partes) return 'Sin fecha'
  return new Date(Number(partes[1]), Number(partes[2]) - 1, Number(partes[3])).toLocaleDateString('es-PE', { day: '2-digit', month: 'short', year: 'numeric' })
}
abrirVencimientos = () => irExpedientes({ vence_en_dias: historico.value.vigencia?.dias_consultados || periodoDias.value })
async function cargarPersonas(anio = anioSeleccionado.value) { const res = await api.get('/dashboard/personas', { params: { busqueda: filtrosPersonas.value.busqueda || undefined, estado: filtrosPersonas.value.estado || undefined, anio: anio || undefined, limite: 25 } }); return res.data }
