async function seleccionarAnio(anio) { anioSeleccionado.value = anio; await cargarTodo(); await seleccionarAlerta(alertaActiva.value) }; async function seleccionarPeriodo(dias) { periodoDias.value = dias; periodoManual.value = null; const version = ++cargaVersion; const clave = `${anioSeleccionado.value || 'todos'}:${dias}`; const cacheado = cacheHistorico.get(clave); if (cacheado && Date.now() - cacheado.fecha < 120000) { historico.value = cacheado.historico; return } cargando.value = true; error.value = ''; try { const res = await api.get('/dashboard/seguimiento-historico', { params: { anio: anioSeleccionado.value || undefined, dias } }); if (version !== cargaVersion) return; historico.value = res.data; cacheHistorico.set(clave, { fecha: Date.now(), historico: res.data }) } catch (err) { if (version === cargaVersion) error.value = err.response?.data?.detail || 'No se pudo actualizar la vigencia.' } finally { if (version === cargaVersion) cargando.value = false } }; async function aplicarPeriodoManual() { const dias = Number(periodoManual.value); if (!Number.isInteger(dias) || dias < 1 || dias > 730) { error.value = 'Ingresa entre 1 y 730 días.'; return }; await seleccionarPeriodo(dias) }; async function buscarPersonas() { try { personas.value = await cargarPersonas() } catch (err) { error.value = err.response?.data?.detail || 'No se pudo buscar personas.' } }; function abrirVencimientos() { irExpedientes({ vence_en_dias: historico.value.vigencia?.vence_periodo || periodoDias.value }) }
function horaEvento(fecha) { return fecha ? new Date(`${fecha}${fecha.endsWith('Z') ? '' : 'Z'}`).toLocaleTimeString('es-PE', { hour: '2-digit', minute: '2-digit' }) : '' }
onMounted(async () => { await cargarTodo(); relojIntervalo = window.setInterval(() => { ahora.value = new Date() }, 1000) })
