ate-columns:1.25rem minmax(0,1fr) auto; align-items:center; gap:.4rem; border:1px solid var(--border); border-radius:.4rem; padding:.48rem .55rem; color:rgb(71 85 105); font-size:.6rem; text-align:left; }.dark .alert-tab { color:rgb(203 213 225); }.alert-tab:hover { border-color:rgb(148 163 184); }.alert-tab.active { border-color:#12356d; background:rgb(239 246 255); color:#12356d; box-shadow:inset 0 0 0 1px #12356d; }.dark .alert-tab.active { border-color:rgb(103 232 249); background:rgb(8 47 73 / .45); color:rgb(207 250 254); box-shadow:inset 0 0 0 1px rgb(103 232 249); }.alert-tab > span { overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }.alert-tab b { color:inherit; font-size:.78rem; }.alert-tab.critical > i { color:#ef4444; }.alert-tab.warning > i { color:#d97706; }.alert-tab.attention > i { color:#2563eb; }.alert-tab.long > i { color:#9333ea; }.alert-tab.warning,.alert-tab.critical,.alert-tab.attention,.alert-tab.long { background:transparent; }.alert-tab.warning.active,.alert-tab.critical.active,.alert-tab.attention.active,.alert-tab.long.active { background:rgb(239 246 255); }.dark .alert-tab.warning.active,.dark .alert-tab.critical.active,.dark .alert-tab.attention.active,.dark .alert-tab.long.active { background:rgb(8 47 73 / .45); }.alert-list { max-height:17rem; overflow-y:auto; overscroll-behavior:contain; scrollbar-gutter:stable; }.alert-list button { display:flex; width:100%; align-items:center; justify-content:space-between; gap:1rem; border-bottom:1px solid var(--border); padding:.58rem .9rem; text-align:left; }.alert-list button:hover { background:rgb(248 250 252); }.dark .alert-list button:hover { background:rgb(30 41 59); }.alert-list strong,.alert-list small { display:block; }.alert-list strong { color:rgb(15 23 42); font-size:.68rem; }.dark .alert-list strong { color:white; }.alert-list small,.alert-list b,.alert-list p { color:rgb(100 116 139); font-size:.58rem; }.alert-list b { flex:0 0 auto; color:#b45309; }.alert-list p { padding:.8rem .9rem; }.control-grid .service-panel { display:grid; grid-template-rows:auto 1fr auto; gap:.45rem; padding:1rem; }.control-grid .service-panel .service-metrics { display:grid; grid-template-columns:1fr 1fr; align-content:start; gap:.45rem; margin:0; }.control-grid .service-panel .service-metrics span { min-width:0; border:1px solid rgb(255 255 255 / .16); border-radius:.35rem; padding:.42rem .48rem; }.control-grid .service-panel .service-metrics span:last-child { grid-column:1/-1; }.control-grid .service-panel .service-metrics small { font-size:.53rem; }.control-grid .service-panel .service-metrics b { margin-top:.1rem; font-size:.68rem; }.control-grid .rhythm-panel .chart-legend { display:flex; flex-wrap:wrap; max-height:2.1rem; gap:.25rem; overflow-y:auto; }.control-grid .rhythm-panel .chart-legend button { display:flex; align-items:center; gap:.22rem; border:1px solid transparent; border-radius:.25rem; padding:.13rem .28rem; color:rgb(100 116 139); font-size:.52rem; }.dark .control-grid .rhythm-panel .chart-legend button { color:rgb(148 163 184); }.control-grid .rhythm-panel .chart-legend button.active { border-color:#0ea5e9; color:#0369a1; }.dark .control-grid .rhythm-panel .chart-legend button.active { color:rgb(125 211 252); }.control-grid .rhythm-panel .chart-legend i { flex:0 0 auto; }
